import glob
import os
from pathlib import Path

import geopandas as gpd
import pandas as pd
import pyproj
from shapely.geometry import box
from shapely.ops import transform

# Input Urban Atlas change packages. The city names are inferred from this folder structure.
INPUT_GPKG_GLOB = 'unziped_files_LU_change/*/*/Data/*.gpkg'
# Input centroid CSVs generated by calculate_change_centroids_MoreCity.py.
CENTROID_DIR = 'outputs/urbanchange_centroids_dir'
# Output CSVs storing per-centroid bounding boxes for satellite-image download.
OUTPUT_DIR = 'outputs/urbanchange_centroids_dir'
# Half-side length of the square bbox around each centroid, in meters.
BBOX_EXTENSION_METERS = 10
WGS84 = 'EPSG:4326'


def latlon_to_utm_crs(lat, lon):
    zone = int((lon + 180) / 6) + 1
    south = lat < 0
    epsg_code = 32600 + zone if not south else 32700 + zone
    return pyproj.CRS(f'EPSG:{epsg_code}')


def create_bbox_wgs84(point, extension_m):
    lat, lon = point.y, point.x
    utm_crs = latlon_to_utm_crs(lat, lon)
    wgs84_crs = pyproj.CRS(WGS84)

    project_to_utm = pyproj.Transformer.from_crs(wgs84_crs, utm_crs, always_xy=True).transform
    project_to_wgs84 = pyproj.Transformer.from_crs(utm_crs, wgs84_crs, always_xy=True).transform
    x, y = transform(project_to_utm, point).x, transform(project_to_utm, point).y

    bbox_utm = box(x - extension_m, y - extension_m, x + extension_m, y + extension_m)
    bbox_wgs84 = transform(project_to_wgs84, bbox_utm)
    minx, miny, maxx, maxy = bbox_wgs84.bounds
    return pd.Series({'min_lon': minx, 'min_lat': miny, 'max_lon': maxx, 'max_lat': maxy})


def main():
    gpkg_list = glob.glob(INPUT_GPKG_GLOB)
    os.makedirs(OUTPUT_DIR, exist_ok=True)

    for gpkg_path in gpkg_list:
        city_name = Path(gpkg_path).parts[1]
        csv_path = os.path.join(CENTROID_DIR, f'{city_name}_urban_filtered_centroids_wgs84.csv')
        output_csv_path = os.path.join(OUTPUT_DIR, f'{city_name}_output_bboxes_with_all_attributes.csv')

        print(
            f'A square bbox with side length {2 * BBOX_EXTENSION_METERS} meters will be generated for each centroid.'
        )

        if not os.path.exists(csv_path):
            print(f'Missing centroid file: {csv_path}')
            continue

        df = pd.read_csv(csv_path)
        print(f'Successfully read the CSV file with {len(df)} points.')
        print(df.head())

        gdf = gpd.GeoDataFrame(
            df,
            geometry=gpd.points_from_xy(df.longitude, df.latitude),
            crs=WGS84,
        )

        bbox_df = gdf.geometry.apply(lambda point: create_bbox_wgs84(point, BBOX_EXTENSION_METERS))
        final_df = pd.concat([df, bbox_df], axis=1)

        final_df.to_csv(output_csv_path, index=False)
        print(f"Successfully generated bboxes and saved them to '{output_csv_path}'")
        print(final_df.head())


if __name__ == '__main__':
    main()
